+    EXPECT_TRUE(ParseFails(p, "\x01"));
+  }
+
+  TEST(ParserTypes, Int8) {
+    Parser p = Int8();
+    EXPECT_TRUE(ParsesTo(p, "\x88", "s-0x78"));
