+
+  TEST(ParserTypes, Ignore) {
+    Parser p = Sequence(Ch('a'), Ignore(Ch('b')), Ch('c'), NULL);
+    EXPECT_TRUE(ParsesTo(p, "abc", "(u0x61 u0x63)"));
