+
+  TEST(ParserTypes, SepBy) {
+    Parser p = SepBy(Choice(Ch('1'), Ch('2'), Ch('3'), NULL), Ch(','));
+    EXPECT_TRUE(ParsesTo(p, "1,2,3", "(u0x31 u0x32 u0x33)"));
+    EXPECT_TRUE(ParsesTo(p, "1,3,2", "(u0x31 u0x33 u0x32)"));
+    EXPECT_TRUE(ParsesTo(p, "1,3", "(u0x31 u0x33)"));
