+    p.bind(Choice(Sequence(Ch('a'), p, NULL), Epsilon(), NULL));
+    EXPECT_TRUE(ParsesTo(p, "a", "(u0x61)"));
+    EXPECT_TRUE(ParsesTo(p, "aa", "(u0x61 (u0x61))"));
